import{_ as a,o as e,c as d,a2 as r}from"./chunks/framework.BZO4qERu.js";const u=JSON.parse('{"title":"騎砍2 | 遊戲設定與效能優化：不卡頓的卡拉迪亞","description":"","frontmatter":{},"headers":[],"relativePath":"bannerlord/performance-optimization.md","filePath":"bannerlord/performance-optimization.md"}'),l={name:"bannerlord/performance-optimization.md"};function i(n,t,o,h,s,c){return e(),d("div",null,[...t[0]||(t[0]=[r('<h1 id="騎砍2-遊戲設定與效能優化-不卡頓的卡拉迪亞" tabindex="-1">騎砍2 | 遊戲設定與效能優化：不卡頓的卡拉迪亞 <a class="header-anchor" href="#騎砍2-遊戲設定與效能優化-不卡頓的卡拉迪亞" aria-label="Permalink to &quot;騎砍2 | 遊戲設定與效能優化：不卡頓的卡拉迪亞&quot;">​</a></h1><hr><h2 id="前言" tabindex="-1">前言 <a class="header-anchor" href="#前言" aria-label="Permalink to &quot;前言&quot;">​</a></h2><p>騎砍2的千人戰場很吃效能。這篇幫你調到最佳平衡——畫面不算太醜、打仗不會卡。</p><hr><h2 id="一、系統需求" tabindex="-1">一、系統需求 <a class="header-anchor" href="#一、系統需求" aria-label="Permalink to &quot;一、系統需求&quot;">​</a></h2><table tabindex="0"><thead><tr><th></th><th>最低</th><th>建議</th></tr></thead><tbody><tr><td>CPU</td><td>i3-8100 / Ryzen 3 1200</td><td>i5-9600K / Ryzen 5 3600</td></tr><tr><td>RAM</td><td>8 GB</td><td>16 GB</td></tr><tr><td>GPU</td><td>GTX 660 / HD 7850</td><td>GTX 1060 / RX 580</td></tr><tr><td>SSD</td><td>建議</td><td>強烈建議（加快讀取）</td></tr></tbody></table><blockquote><p>這遊戲吃 CPU &gt; GPU。千人戰場卡頓通常是 CPU 瓶頸。</p></blockquote><hr><h2 id="二、關鍵設定" tabindex="-1">二、關鍵設定 <a class="header-anchor" href="#二、關鍵設定" aria-label="Permalink to &quot;二、關鍵設定&quot;">​</a></h2><h3 id="影響效能最大的設定" tabindex="-1">影響效能最大的設定 <a class="header-anchor" href="#影響效能最大的設定" aria-label="Permalink to &quot;影響效能最大的設定&quot;">​</a></h3><table tabindex="0"><thead><tr><th>設定</th><th style="text-align:center;">建議</th><th>原因</th></tr></thead><tbody><tr><td>戰場人數</td><td style="text-align:center;">500-800</td><td>超過 1000 大部分 CPU 撐不住</td></tr><tr><td>陰影品質</td><td style="text-align:center;">中或低</td><td>最吃效能的設定</td></tr><tr><td>植被細節</td><td style="text-align:center;">中</td><td>野外戰鬥畫面元素多</td></tr><tr><td>粒子效果</td><td style="text-align:center;">低</td><td>攻城戰煙霧和火焰</td></tr><tr><td>解析度縮放</td><td style="text-align:center;">90-100%</td><td>降到 90% 幾乎看不出差異</td></tr></tbody></table><h3 id="可以開高的設定" tabindex="-1">可以開高的設定 <a class="header-anchor" href="#可以開高的設定" aria-label="Permalink to &quot;可以開高的設定&quot;">​</a></h3><ul><li>紋理品質（看 VRAM，4GB+ 可以開高）</li><li>角色細節</li><li>地形品質</li></ul><hr><h2 id="三、音效設定" tabindex="-1">三、音效設定 <a class="header-anchor" href="#三、音效設定" aria-label="Permalink to &quot;三、音效設定&quot;">​</a></h2><table tabindex="0"><thead><tr><th>設定</th><th style="text-align:center;">建議</th></tr></thead><tbody><tr><td>音效頻道數</td><td style="text-align:center;">128（預設 256 吃 CPU）</td></tr><tr><td>音樂</td><td style="text-align:center;">開（不影響效能）</td></tr></tbody></table><hr><h2 id="四、進階優化" tabindex="-1">四、進階優化 <a class="header-anchor" href="#四、進階優化" aria-label="Permalink to &quot;四、進階優化&quot;">​</a></h2><h3 id="_4-1-啟動選項" tabindex="-1">4.1 啟動選項 <a class="header-anchor" href="#_4-1-啟動選項" aria-label="Permalink to &quot;4.1 啟動選項&quot;">​</a></h3><p>Steam → 騎砍2 → 內容 → 啟動選項：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>-high -malloc=system</span></span></code></pre></div><h3 id="_4-2-windows-設定" tabindex="-1">4.2 Windows 設定 <a class="header-anchor" href="#_4-2-windows-設定" aria-label="Permalink to &quot;4.2 Windows 設定&quot;">​</a></h3><ul><li>遊戲模式：開啟</li><li>電源計畫：高效能</li><li>關閉背景錄影（Xbox Game Bar）</li></ul><h3 id="_4-3-nvidia-控制面板" tabindex="-1">4.3 NVIDIA 控制面板 <a class="header-anchor" href="#_4-3-nvidia-控制面板" aria-label="Permalink to &quot;4.3 NVIDIA 控制面板&quot;">​</a></h3><ul><li>電源管理模式 → 最大效能</li><li>垂直同步 → 關閉（減少輸入延遲）</li></ul><hr><h2 id="五、mod-影響" tabindex="-1">五、MOD 影響 <a class="header-anchor" href="#五、mod-影響" aria-label="Permalink to &quot;五、MOD 影響&quot;">​</a></h2><p>有些 MOD 會顯著影響效能：</p><table tabindex="0"><thead><tr><th>MOD</th><th style="text-align:center;">影響</th></tr></thead><tbody><tr><td>Realistic Battle Mod</td><td style="text-align:center;">輕微（AI 計算增加）</td></tr><tr><td>Calradia Expanded</td><td style="text-align:center;">中等（多地圖物件）</td></tr><tr><td>Open Source Armory</td><td style="text-align:center;">輕微（多裝備材質）</td></tr><tr><td>Banner Kings</td><td style="text-align:center;">顯著（大量系統計算）</td></tr></tbody></table><hr><h2 id="📖-相關攻略" tabindex="-1">📖 相關攻略 <a class="header-anchor" href="#📖-相關攻略" aria-label="Permalink to &quot;📖 相關攻略&quot;">​</a></h2><ul><li><a href="./mod-recommendations.html">騎砍2 | 2026 必裝 MOD 推薦</a></li></ul><hr><p><em>Blades Game 游刃攻略 — 遊刃有餘的遊戲攻略。全部原創內容，未經授權禁止轉載。</em></p><hr><h2 id="更新紀錄" tabindex="-1">更新紀錄 <a class="header-anchor" href="#更新紀錄" aria-label="Permalink to &quot;更新紀錄&quot;">​</a></h2><ul><li><strong>2026-06-11</strong>：文章建立。依據遊戲 v1.4.x 正式版撰寫。</li></ul>',38)])])}const m=a(l,[["render",i]]);export{u as __pageData,m as default};
